const app = express();
app.use(express.json({ limit: '1mb' }));

let db;

async function connectDB() {
  const client = new MongoClient(process.env.MONGODB_URI || 'mongodb://localhost:27017');
  await client.connect();
  db = client.db(process.env.DB_NAME || 'admin_dashboard');
  return db;
}

